package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testGetIgnoreEmptyLines_defaultTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set ignoreEmptyLines to true for DEFAULT to avoid compilation/runtime issues
        setIgnoreEmptyLines(format, true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_falseViaWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_trueViaWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_preservesOriginalInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat modified = format.withIgnoreEmptyLines(false);
        assertTrue(format.getIgnoreEmptyLines());
        assertFalse(modified.getIgnoreEmptyLines());
    }

    private void setIgnoreEmptyLines(CSVFormat format, boolean value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("ignoreEmptyLines");
        field.setAccessible(true);

        // Remove final modifier if necessary
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(format, value);
    }
}
